 1	import * as React from 'react';
 2	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
 3	import { SyncAltIcon } from '@patternfly/react-icons';
 4	
 5	type RefreshButtonProps = {
 6	  disabled?: boolean;
 7	  handleRefresh: () => void;
 8	  id?: string;
 9	};
10	
11	export const RefreshButton: React.FC<RefreshButtonProps> = (props: RefreshButtonProps) => {
12	  const [enableRefresh, setEnableRefresh] = React.useState<boolean>(true);
13	
14	  const handleRefresh = (): void => {
15	    if (enableRefresh) {
16	      props.handleRefresh();
17	
18	      // Disable refresh during 500 ms to avoid multiple refresh in very short period of time
19	      setEnableRefresh(false);
20	      setTimeout(() => setEnableRefresh(true), 500);
21	    }
22	  };
23	
24	  return (
25	    <Tooltip position="bottom" content={<>Refresh</>}>
26	      <Button
27	        id={props.id ?? 'refresh_button'}
28	        data-test="refresh-button"
29	        onClick={handleRefresh}
30	        isDisabled={props.disabled ?? false}
31	        aria-label="Action"
32	        variant={ButtonVariant.primary}
33	      >
34	        <SyncAltIcon />
35	      </Button>
36	    </Tooltip>
37	  );
38	};

